vices.AddInfrastructure();   // Repositories, DbContext\nbuilder.Services.AddPresentation();     // Controllers\n\nvar app = builder.Build();\napp.Run();\n"})}),"\n",(0,t.jsx)(n.hr,{}),"\n",(0,t.jsx)(n.h2,{id:"independencia-del-framework",children:"Independencia del Framework"}),"\n",(0,t.jsx)(n.h3,{id:"qu\xe9-es-independencia-del-framework",children:"\xbfQu\xe9 es Independencia del Framework?"}),"\n",(0,t.jsxs)(n.p,{children:["Principio que establece que ",(0,t.jsx)(n.strong,{children:"el dominio debe estar libre de dependencias a frameworks espec\xedficos"})," (EF Core, ASP.NET, etc.), permitiendo que la l\xf3gica de negocio evolucione independientemente de decisiones tecnol\xf3gicas."]}),"\n",(0,t.jsx)(n.p,{children:(0,t.jsx)(n.strong,{children:"Reglas:"})}),"\n",(0,t.jsxs)(n.ul,{children:["\n",(0,t.jsx)(n.li,{children:"Domain NO referencia EF Core, ASP.NET, Dapper, etc."}),"\n",(0,t.jsx)(n.li,{children:"Domain usa POCOs (Plain Old CLR Objects)"}),"\n",(0,t.jsx)(n.li,{children:"Atributos de frameworks solo en Infrastructure"}),"\n"]}),"\n",(0,t.jsxs)(n.p,{children:[(0,t.jsx)(n.strong,{children:"Beneficios:"}),"\n\u2705 L\xf3gica de negocio portable\n\u2705 Testing sin frameworks\n\u2705 Cambio de tecnolog\xeda sin reescribir dominio"]}),"\n",(0,t.jsx)(n.h3,{id:"ejemplo-comparativo-2",children:"Ejemplo Comparativo"}),"\n",(0,t.jsx)(n.pre,{children:(0,t.jsx)(n.code,{className:"language-csharp",children:'// \u274c MALO: Dominio acoplado a EF Core\n\nusing Microsoft.EntityFrameworkCore; // \u274c Dependencia en Domain\n\n[Table("orders")] // \u274c Atributo de EF Core\npublic class Order\n{\n    [Key] // \u274c Atributo de EF Core\n    public Guid Id { get; set; }\n\n    [Required] // \u274c Data Annotations\n    [MaxLength(100)]\n    public string CustomerName { get; set; }\n\n    [InverseProperty("Order")] // \u274c Configuraci\xf3n EF\n    public virtual ICollection<OrderLine> Lines { get; set; }\n}\n\n// \u2705 BUENO: Dominio independiente\n\n// Domain/Entities/Order.cs (sin using de frameworks)\nnamespace ServiceName.Domain.Entities;\n\npublic class Order // POCO puro\n{\n    public Guid Id { get; private set; }\n    public CustomerName CustomerName { get; private set; } // Value Object\n    private readonly List<OrderLine> _lines = new();\n    public IReadOnlyCollection<OrderLine> Lines => _lines.AsReadOnly();\n\n    private Order() { } // EF Core constructor sin atributos\n\n    public static Result<Order> Create(CustomerName customerName)\n    {\n        if (customerName == null)\n            return Result.Failure<Order>("CustomerName requerido");\n\n        return Result.Success(new Order\n        {\n            Id = Guid.NewGuid(),\n            CustomerName = customerName\n        });\n    }\n}\n\n// Infrastructure/Persistence/Configurations/OrderConfiguration.cs\nusing Microsoft.EntityFrameworkCore; // \u2705 Dependencia solo en Infrastructure\n\npublic class OrderConfiguration : IEntityTypeConfiguration<Order>\n{\n    public void Configure(EntityTypeBuilder<Order> builder)\n    {\n        builder.ToTable("orders");\n        builder.HasKey(o => o.Id);\n\n        builder.OwnsOne(o => o.CustomerName, name =>\n        {\n            name.Property(n => n.Value).HasColumnName("customer_name").HasMaxLength(100);\n        });\n\n        builder.HasMany(typeof(OrderLine))\n            .WithOne()\n            .HasForeignKey("OrderId");\n    }\n}\n'})}),"\n",(0,t.jsx)(n.hr,{}),"\n",(0,t.jsx)(n.h2,{id:"implementaci\xf3n-integrada",children:"Implementaci\xf3n Integrada"}),"\n",(0,t.jsx)(n.h3,{id:"proyecto-completo-con-clean-architecture",children:"Proyecto Completo con Clean Architecture"}),"\n",(0,t.jsx)(n.pre,{children:(0,t.jsx)(n.code,{className:"language-csharp",children:'// ===== DOMAIN LAYER =====\n\n// Domain/ValueObjects/CustomerId.cs\npublic record CustomerId(Guid Value)\n{\n    public static CustomerId New() => new(Guid.NewGuid());\n}\n\n// Domain/Entities/Order.cs\npublic class Order : AggregateRoot<Guid>\n{\n    public CustomerId CustomerId { get; private set; }\n    public Money Total { get; private set; }\n    public OrderStatus Status { get; private set; }\n\n    private readonly List<OrderLine> _lines = new();\n    public IReadOnlyCollection<OrderLine> Lines => _lines.AsReadOnly();\n\n    private Order() { }\n\n    public static Result<Order> Create(CustomerId customerId)\n    {\n        if (customerId == null)\n            return Result.Failure<Order>("CustomerId requerido");\n\n        var order = new Order\n        {\n            Id = Guid.NewGuid(),\n            CustomerId = customerId,\n            Status = OrderStatus.Draft,\n            Total = Money.Zero()\n        };\n\n        order.AddDomainEvent(new OrderCreatedEvent(order.Id));\n\n        return Result.Success(order);\n    }\n\n    public Result AddLine(ProductId productId, Quantity quantity, Money unitPrice)\n    {\n        if (Status != OrderStatus.Draft)\n            return Result.Failure("Solo se pueden agregar l\xedneas en borrador");\n\n        var line = OrderLine.Create(productId, quantity, unitPrice);\n        _lines.Add(line.Value);\n        RecalculateTotal();\n\n        return Result.Success();\n    }\n\n    private void RecalculateTotal()\n    {\n        Total = _lines.Aggregate(Money.Zero(), (sum, l) => sum.Add(l.LineTotal));\n    }\n}\n\n// Domain/Repositories/IOrderRepository.cs (Puerto)\npublic interface IOrderRepository\n{\n    Task<Order?> GetByIdAsync(Guid id);\n    Task SaveAsync(Order order);\n}\n\n// ===== APPLICATION LAYER =====\n\n// Application/Commands/CreateOrderCommand.cs\npublic record CreateOrderCommand(\n    Guid CustomerId,\n    List<OrderLineDto> Lines\n);\n\n// Application/UseCases/CreateOrderUseCase.cs\npublic class CreateOrderUseCase\n{\n    private readonly IOrderRepository _repository;\n    private readonly IValidator<CreateOrderCommand> _validator;\n\n    public CreateOrderUseCase(\n        IOrderRepository repository,\n        IValidator<CreateOrderCommand> validator)\n    {\n        _repository = repository;\n        _validator = validator;\n    }\n\n    public async Task<Result<Guid>> ExecuteAsync(\n        CreateOrderCommand command,\n        CancellationToken ct = default)\n    {\n        var validation = await _validator.ValidateAsync(command, ct);\n        if (!validation.IsValid)\n            return Result.Failure<Guid>(validation.ToString());\n\n        var orderResult = Order.Create(new CustomerId(command.CustomerId));\n        if (orderResult.IsFailure)\n            return Result.Failure<Guid>(orderResult.Error);\n\n        var order = orderResult.Value;\n\n        foreach (var line in command.Lines)\n        {\n            var addResult = order.AddLine(\n                new ProductId(line.ProductId),\n                new Quantity(line.Quantity),\n                new Money(line.UnitPrice, Currency.USD)\n            );\n\n            if (addResult.IsFailure)\n                return Result.Failure<Guid>(addResult.Error);\n        }\n\n        await _repository.SaveAsync(order, ct);\n\n        return Result.Success(order.Id);\n    }\n}\n\n// ===== INFRASTRUCTURE LAYER =====\n\n// Infrastructure/Persistence/ApplicationDbContext.cs\npublic class ApplicationDbContext : DbContext\n{\n    public DbSet<Order> Orders => Set<Order>();\n\n    protected override void OnModelCreating(ModelBuilder modelBuilder)\n    {\n        modelBuilder.ApplyConfigurationsFromAssembly(typeof(ApplicationDbContext).Assembly);\n    }\n}\n\n// Infrastructure/Persistence/Repositories/OrderRepository.cs (Adaptador)\npublic class OrderRepository : IOrderRepository\n{\n    private readonly ApplicationDbContext _context;\n\n    public OrderRepository(ApplicationDbContext context)\n    {\n        _context = context;\n    }\n\n    public async Task<Order?> GetByIdAsync(Guid id)\n    {\n        return await _context.Orders\n            .Include(o => o.Lines)\n            .FirstOrDefaultAsync(o => o.Id == id);\n    }\n\n    public async Task SaveAsync(Order order)\n    {\n        _context.Orders.Add(order);\n        await _context.SaveChangesAsync();\n    }\n}\n\n// Infrastructure/DependencyInjection.cs\npublic static class DependencyInjection\n{\n    public static IServiceCollection AddInfrastructure(\n        this IServiceCollection services,\n        IConfiguration configuration)\n    {\n        services.AddDbContext<ApplicationDbContext>(options =>\n            options.UseNpgsql(configuration.GetConnectionString("DefaultConnection"))\n        );\n\n        services.AddScoped<IOrderRepository, OrderRepository>();\n\n        return services;\n    }\n}\n\n// ===== PRESENTATION LAYER =====\n\n// WebApi/Controllers/OrdersController.cs\n[ApiController]\n[Route("api/v1/orders")]\npublic class OrdersController : ControllerBase\n{\n    private readonly CreateOrderUseCase _useCase;\n\n    [HttpPost]\n    public async Task<IActionResult> CreateOrder(\n        [FromBody] CreateOrderRequest request,\n        CancellationToken ct)\n    {\n        var command = request.ToCommand();\n        var result = await _useCase.ExecuteAsync(command, ct);\n\n        return result.IsSuccess\n            ? CreatedAtAction(nameof(GetOrder), new { id = result.Value },\n                new { OrderId = result.Value })\n            : BadRequest(new { Error = result.Error });\n    }\n\n    [HttpGet("{id:guid}")]\n    public async Task<IActionResult> GetOrder(Guid id)\n    {\n        // Implementaci\xf3n...\n        return Ok();\n    }\n}\n\n// WebApi/Program.cs\nvar builder = WebApplication.CreateBuilder(args);\n\nbuilder.Services.AddControllers();\nbuilder.Services.AddApplication();\nbuilder.Services.AddInfrastructure(builder.Configuration);\n\nvar app = builder.Build();\napp.MapControllers();\napp.Run();\n'})}),"\n",(0,t.jsx)(n.hr,{}),"\n",(0,t.jsx)(n.h2,{id:"matriz-de-decisi\xf3n",children:"Matriz de Decisi\xf3n"}),"\n",(0,t.jsxs)(n.table,{children:[(0,t.jsx)(n.thead,{children:(0,t.jsxs)(n.tr,{children:[(0,t.jsx)(n.th,{children:"Escenario"}),(0,t.jsx